  CONSTRAINT `fk_asist_just_por` FOREIGN KEY (`justificado_por`) REFERENCES `personal` (`id`),
  CONSTRAINT `fk_asist_justificacion` FOREIGN KEY (`id_justificacion`) REFERENCES `justificaciones` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
